347	njs_int_t
348	njs_function_native_frame(njs_vm_t *vm, njs_function_t *function,
349	    const njs_value_t *this, const njs_value_t *args, njs_uint_t nargs,
350	    njs_bool_t ctor)
351	{
352	    size_t              size;
353	    njs_value_t         *value;
354	    njs_native_frame_t  *frame;
355	
356	    size = NJS_NATIVE_FRAME_SIZE + (1 /* this */ + nargs) * sizeof(njs_value_t);
357	
358	    frame = njs_function_frame_alloc(vm, size);
359	    if (njs_slow_path(frame == NULL)) {
360	        return NJS_ERROR;
361	    }
362	
363	    frame->function = function;
364	    frame->nargs = nargs;
365	    frame->ctor = ctor;
366	    frame->native = 1;
367	    frame->pc = NULL;
368	
369	    value = (njs_value_t *) ((u_char *) frame + NJS_NATIVE_FRAME_SIZE);
370	
371	    njs_value_assign(value++, this++);
372	
373	    frame->arguments = value;
