660	njs_int_t
661	njs_function_frame_invoke(njs_vm_t *vm, njs_value_t *retval)
662	{
663	    njs_native_frame_t  *frame;
664	
665	    frame = vm->top_frame;
666	
667	    if (njs_function_object_type(vm, frame->function)
668	        == NJS_OBJ_TYPE_ASYNC_FUNCTION)
669	    {
670	        return njs_async_function_frame_invoke(vm, retval);
671	    }
