692	njs_int_t
693	njs_function_frame_save(njs_vm_t *vm, njs_frame_t *frame, u_char *pc)
694	{
695	    size_t                 args_count, value_count, n;
696	    njs_value_t            **map, *value, **current_map;
697	    njs_function_t         *function;
698	    njs_native_frame_t     *active, *native;
699	    njs_function_lambda_t  *lambda;
700	
701	    *frame = *vm->active_frame;
702	
703	    frame->previous_active_frame = NULL;
704	
705	    native = &frame->native;
706	    native->size = 0;
707	    native->free = NULL;
708	    native->free_size = 0;
709	
710	    active = &vm->active_frame->native;
711	    function = active->function;
712	    lambda = function->u.lambda;
713	
714	    args_count = njs_max(native->nargs, lambda->nargs);
715	    value_count = args_count + lambda->nlocal;
716	
717	    /*
718	     * We need to save the current frame state because it will be freed
719	     * when the function returns.
720	     *
721	     *  To detect whether a value is captured as a closure,
722	     *  we check whether the pointer is within the frame. In this case
723	     *  the pointer is copied as is because the value it points to
724	     *  is already allocated in the heap and will not be freed.
725	     *  See njs_function_capture_closure() and njs_function_lambda_frame()
726	     *  for details.
727	     */
728	
729	    map = (njs_value_t **) ((u_char *) native + NJS_FRAME_SIZE);
730	    value = (njs_value_t *) (map + value_count);
731	
732	    current_map = (njs_value_t **) ((u_char *) active + NJS_FRAME_SIZE);
733	
734	    for (n = 0; n < value_count; n++) {
735	        if (njs_is_value_allocated_on_frame(active, current_map[n])) {
736	            map[n] = &value[n];
737	            njs_value_assign(&value[n], current_map[n]);
738	
739	        } else {
740	            map[n] = current_map[n];
741	        }
742	    }
743	
744	    native->arguments = value;
745	    native->local = map + args_count;
746	    native->pc = pc;
747	
748	    return NJS_OK;
749	}
