830	
831	njs_int_t
832	njs_function_capture_global_closures(njs_vm_t *vm, njs_function_t *function)
833	{
834	    uint32_t               n;
835	    njs_value_t            *value, **refs, **global;
836	    njs_index_t            *indexes, index;
837	    njs_native_frame_t     *native;
838	    njs_function_lambda_t  *lambda;
839	
840	    lambda = function->u.lambda;
841	
842	    if (lambda->nclosures == 0) {
843	        return NJS_OK;
844	    }
845	
846	    native = vm->top_frame;
847	
848	    while (native->previous->function != NULL) {
849	        native = native->previous;
850	    }
851	
852	    indexes = lambda->closures;
853	    refs = njs_function_closures(function);
854	
855	    global = vm->levels[NJS_LEVEL_GLOBAL];
856	
857	    n = lambda->nclosures;
858	
859	    while (n > 0) {
860	        n--;
861	
862	        index = indexes[n];
863	
864	        switch (njs_scope_index_type(index)) {
865	        case NJS_LEVEL_LOCAL:
866	            value = njs_function_closure_value(vm, native, native->local,
867	                                               index);
868	            break;
869	
870	        case NJS_LEVEL_GLOBAL:
871	            value = njs_function_closure_value(vm, native, global, index);
872	            break;
873	
874	        default:
875	            njs_type_error(vm, "unexpected value type for closure \"%uD\"",
876	                           njs_scope_index_type(index));
877	            return NJS_ERROR;
878	        }
879	
880	        if (njs_slow_path(value == NULL)) {
881	            return NJS_ERROR;
882	        }
883	
884	        refs[n] = value;
885	    }
886	
887	    function->closure_copied = 1;
888	
889	    return NJS_OK;
890	}
