926	/*
927	 * The "prototype" property of user defined functions is created on
928	 * demand in private hash of the functions by the "prototype" getter.
929	 * The getter creates a copy of function which is private to nJSVM,
930	 * adds a "prototype" object property to the copy, and then adds a
931	 * "constructor" property in the prototype object.  The "constructor"
932	 * property points to the copy of function:
933	 *   "F.prototype.constructor === F"
934	 */
935	
936	njs_int_t
937	njs_function_prototype_create(njs_vm_t *vm, njs_object_prop_t *prop,
938	    uint32_t unused, njs_value_t *value, njs_value_t *setval,
939	    njs_value_t *retval)
940	{
941	    njs_value_t   *proto, proto_value, *cons;
942	    njs_object_t  *prototype;
943	
944	    if (setval == NULL) {
945	        prototype = njs_object_alloc(vm);
946	        if (njs_slow_path(prototype == NULL)) {
947	            return NJS_ERROR;
948	        }
949	
950	        njs_set_object(&proto_value, prototype);
951	
952	        setval = &proto_value;
953	    }
954	
955	    proto = njs_function_property_prototype_set(vm, njs_object_hash(value),
956	                                                setval);
957	    if (njs_slow_path(proto == NULL)) {
958	        return NJS_ERROR;
959	    }
960	
961	    if (setval == &proto_value && njs_is_object(proto)) {
962	        /* Only in getter context. */
963	        cons = njs_property_constructor_set(vm, njs_object_hash(proto), value);
964	        if (njs_slow_path(cons == NULL)) {
965	            return NJS_ERROR;
966	        }
967	    }
968	
969	    *retval = *proto;
970	
971	    return NJS_OK;
972	}
