974	
975	njs_int_t
976	njs_function_constructor(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
977	    njs_index_t async, njs_value_t *retval)
978	{
979	    njs_chb_t               chain;
980	    njs_int_t               ret;
981	    njs_str_t               str, file;
982	    njs_uint_t              i;
983	    njs_value_t             name;
984	    njs_parser_t            parser;
985	    njs_vm_code_t           *code;
986	    njs_function_t          *function;
987	    njs_generator_t         generator;
988	    njs_parser_node_t       *node;
989	    njs_function_lambda_t   *lambda;
990	    const njs_token_type_t  *type;
991	
992	    static const njs_token_type_t  safe_ast[] = {
993	        NJS_TOKEN_END,
994	        NJS_TOKEN_FUNCTION_EXPRESSION,
995	        NJS_TOKEN_STATEMENT,
996	        NJS_TOKEN_RETURN,
997	        NJS_TOKEN_THIS,
998	        NJS_TOKEN_ILLEGAL
999	    };
1000	
1001	    static const njs_token_type_t  safe_ast_async[] = {
1002	        NJS_TOKEN_END,
1003	        NJS_TOKEN_ASYNC_FUNCTION_EXPRESSION,
1004	        NJS_TOKEN_STATEMENT,
1005	        NJS_TOKEN_RETURN,
1006	        NJS_TOKEN_THIS,
1007	        NJS_TOKEN_ILLEGAL
1008	    };
1009	
1010	    if (!vm->options.unsafe && nargs != 2) {
1011	        goto fail;
1012	    }
1013	
1014	    NJS_CHB_MP_INIT(&chain, njs_vm_memory_pool(vm));
1015	
1016	    if (async) {
1017	        njs_chb_append_literal(&chain, "(async function(");
1018	
1019	    } else {
1020	        njs_chb_append_literal(&chain, "(function(");
1021	    }
1022	
1023	    for (i = 1; i < nargs - 1; i++) {
1024	        ret = njs_value_to_chain(vm, &chain, njs_argument(args, i));
1025	        if (njs_slow_path(ret < NJS_OK)) {
1026	            return ret;
1027	        }
1028	
1029	        if (i != (nargs - 2)) {
1030	            njs_chb_append_literal(&chain, ",");
1031	        }
1032	    }
1033	
1034	    njs_chb_append_literal(&chain, "\n){\n");
1035	
1036	    if (nargs > 1) {
1037	        ret = njs_value_to_chain(vm, &chain, njs_argument(args, nargs - 1));
1038	        if (njs_slow_path(ret < NJS_OK)) {
1039	            return ret;
1040	        }
1041	    }
1042	
1043	    njs_chb_append_literal(&chain, "\n})");
1044	
1045	    ret = njs_chb_join(&chain, &str);
1046	    if (njs_slow_path(ret != NJS_OK)) {
1047	        njs_memory_error(vm);
1048	        return NJS_ERROR;
1049	    }
1050	
1051	    file = njs_str_value("runtime");
1052	
1053	    ret = njs_parser_init(vm, &parser, NULL, &file, str.start,
1054	                          str.start + str.length);
1055	    if (njs_slow_path(ret != NJS_OK)) {
1056	        return ret;
1057	    }
1058	
1059	    ret = njs_parser(vm, &parser);
1060	    if (njs_slow_path(ret != NJS_OK)) {
1061	        return ret;
1062	    }
1063	
1064	    if (!vm->options.unsafe) {
1065	        /*
1066	         * Safe mode exception:
1067	         * "(new Function('return this'))" is often used to get
1068	         * the global object in a portable way.
1069	         */
1070	
1071	        node = parser.node;
1072	        type = (async) ? &safe_ast_async[0] : &safe_ast[0];
1073	
1074	        for (; *type != NJS_TOKEN_ILLEGAL; type++, node = node->right) {
1075	            if (node == NULL) {
1076	                goto fail;
1077	            }
1078	
1079	            if (node->left != NULL
1080	                && node->token_type != NJS_TOKEN_FUNCTION_EXPRESSION
1081	                && node->left->token_type != NJS_TOKEN_NAME)
1082	            {
1083	                goto fail;
1084	            }
1085	
1086	            if (node->token_type != *type) {
1087	                goto fail;
1088	            }
1089	        }
1090	    }
1091	
1092	    ret = njs_generator_init(&generator, &file, 0, 1);
1093	    if (njs_slow_path(ret != NJS_OK)) {
1094	        njs_internal_error(vm, "njs_generator_init() failed");
1095	        return NJS_ERROR;
1096	    }
1097	
1098	    code = njs_generate_scope(vm, &generator, parser.scope,
1099	                              &njs_entry_anonymous);
1100	    if (njs_slow_path(code == NULL)) {
1101	        if (!njs_is_error(retval)) {
1102	            njs_internal_error(vm, "njs_generate_scope() failed");
1103	        }
1104	
1105	        return NJS_ERROR;
1106	    }
1107	
1108	    njs_chb_destroy(&chain);
1109	
1110	    if ((code->end - code->start)
1111	        != (sizeof(njs_vmcode_function_t) + sizeof(njs_vmcode_return_t))
1112	        || ((njs_vmcode_generic_t *) code->start)->code != NJS_VMCODE_FUNCTION)
1113	    {
1114	        njs_syntax_error(vm, "single function literal required");
1115	        return NJS_ERROR;
1116	    }
1117	
1118	    lambda = ((njs_vmcode_function_t *) code->start)->lambda;
1119	
1120	    function = njs_function_alloc(vm, lambda, (njs_bool_t) async);
1121	    if (njs_slow_path(function == NULL)) {
1122	        return NJS_ERROR;
1123	    }
1124	
1125	    function->global = 1;
1126	    function->global_this = 1;
1127	    function->args_count = lambda->nargs - lambda->rest_parameters;
1128	
1129	    njs_atom_to_value(vm, &name, NJS_ATOM_STRING_anonymous);
1130	
1131	    ret = njs_function_name_set(vm, function, &name, NULL);
1132	    if (njs_slow_path(ret == NJS_ERROR)) {
1133	        return ret;
1134	    }
1135	
1136	    njs_set_function(retval, function);
1137	
1138	    return NJS_OK;
1139	
1140	fail:
1141	
1142	    njs_type_error(vm, "function constructor is disabled in \"safe\" mode");
1143	    return NJS_ERROR;
1144	}
