1234	static njs_int_t
1235	njs_function_prototype_apply(njs_vm_t *vm, njs_value_t *args, njs_uint_t nargs,
1236	    njs_index_t unused, njs_value_t *retval)
1237	{
1238	    int64_t         i, length;
1239	    njs_int_t       ret;
1240	    njs_value_t     *this, *arr_like;
1241	    njs_array_t     *arr;
1242	    njs_function_t  *func;
1243	
1244	    if (!njs_is_function(njs_argument(args, 0))) {
1245	        njs_type_error(vm, "\"this\" argument is not a function");
1246	        return NJS_ERROR;
1247	    }
1248	
1249	    func = njs_function(njs_argument(args, 0));
1250	    this = njs_arg(args, nargs, 1);
1251	    arr_like = njs_arg(args, nargs, 2);
1252	
1253	    if (njs_is_null_or_undefined(arr_like)) {
1254	        length = 0;
1255	        goto activate;
1256	    }
1257	
1258	    if (njs_slow_path(!njs_is_object(arr_like))) {
1259	        njs_type_error(vm, "second argument is not an array-like object");
1260	        return NJS_ERROR;
1261	    }
1262	
1263	    ret = njs_object_length(vm, arr_like, &length);
1264	    if (njs_slow_path(ret != NJS_OK)) {
1265	        return ret;
1266	    }
1267	
1268	    if (njs_slow_path(length > 1024)) {
1269	        njs_internal_error(vm, "argument list is too long");
1270	        return NJS_ERROR;
1271	    }
1272	
1273	    arr = njs_array_alloc(vm, 1, length, NJS_ARRAY_SPARE);
1274	    if (njs_slow_path(arr == NULL)) {
1275	        return NJS_ERROR;
1276	    }
1277	
1278	    args = arr->start;
1279	
1280	    for (i = 0; i < length; i++) {
1281	        ret = njs_value_property_i64(vm, arr_like, i, &args[i]);
1282	        if (njs_slow_path(ret == NJS_ERROR)) {
1283	            return ret;
1284	        }
1285	    }
1286	
1287	activate:
1288	
1289	    return njs_function_call(vm, func, this, args, length, retval);
1290	}
